from pickletools import uint8import cv2import numpy as npimport imageioimport torchimport torch.utils.data as data#import SimpleITK as sitkfrom abc import abstractmethodfrom sympy.codegen.ast import nonefrom .base_dataset import BaseDatasetimport os import randomclass SRBenchmark(BaseDataset):    def __init__(self,args,test_dataset_name=None):        super(SRBenchmark,self).__init__(args,test_dataset_name)        self.dataset_image_pathfile = os.path.join(args.dataset_path,'benchmark',test_dataset_name,test_dataset_name+".txt")        self.get_path_from_txt()        self.resize_traindata = args.resize_traindata        self.scale = args.scale        self.test_dataset_name = test_dataset_name    def get_path_from_txt(self):        """        the image and gt filepoath will read from self.dataset_image_pathfile        and save in self.image_path_list\self.gt_path_list        """        with open(self.dataset_image_pathfile,'r') as f:            lines = f.readlines()            for i in range(0,len(lines),2):                self.image_path_list.append(lines[i].rstrip())                self.gt_path_list.append(lines[i+1].rstrip())    def crop_image(self,img):        h,w = img.shape        (h1,h2,w1,w2) = (174,766,449,1169)        if h2>h :            h2 = h        if w2>w:            w2 = w         img = img[h1:h2,w1:w2]        return img    def __len__(self):        return len(self.image_path_list)    def __getitem__(self, idx):        idx = idx % len(self.image_path_list)        image = self.image_path_list[idx]        gt = self.gt_path_list[idx]        tensor_image,tensor_gt,nameext  = self.load_file(image,gt)        return tensor_image, tensor_gt,nameext    def read_file(self,image,gt):        '''        this define the image is one channel , if you want set rgb channel the imread(path) neednot (path,0)        '''        image_array = cv2.imread(image,0)        gt_array = cv2.imread(gt,0)      #  print(image,image_array.shape)        if image_array is None or gt_array is None:            print(image ,"or ",gt,"is false check ")            return   None, None        return   image_array ,gt_array    def resize_image(self, image, mode=None):        def _resize(s):            if mode == "near":                return cv2.resize(s, (self.resize_traindata, self.resize_traindata), interpolation=cv2.INTER_NEAREST)            return cv2.resize(s, (self.resize_traindata, self.resize_traindata))        ret = _resize(image)        return ret    def get_patch(self,img_in, img_tar):        ih, iw = img_in.shape[:2]        hp = self.patch_size        wp = self.patch_size        ix = random.randrange(0, iw - wp + 1)        iy = random.randrange(0, ih - hp + 1)        tx, ty = self.scale * ix, self.scale * iy        img_in = img_in[iy:iy + hp, ix:ix + wp]        img_tar = img_tar[ty:ty + hp*self.scale, tx:tx + wp*self.scale]        return img_in, img_tar    def augment_patch(self, image,gt, hflip=True, rot=True):        # if the patch_size = None the augment will be error because the image has filp and image 2 no flip the batch will be wrong        hflip = hflip and random.random() < 0.5        vflip = rot and random.random() < 0.5        rot90 = rot and random.random() < 0.5        if self.light_change == 1 and random.random() < 0.5:            light_gain = [-55, -45, -20, -10, 10, 20, 45, 55]            light = random.choice(light_gain)        else:            light = 0        def _augment(img):            if hflip: img = img[:, ::-1]            if vflip: img = img[::-1, :]            if rot90: img = img.transpose(1, 0)            if light != 0:                imgf = img.astype(float)  # numpy  20   np.float -> float                imgf_gain = imgf + light                imgf_gain_high = (imgf_gain > 254)                imgf_gain[imgf_gain_high] = 255                img = imgf_gain.astype(int)  # numpy  20   np.int -> int            return img        return _augment(image)    def load_file(self,image,gt):        # patch 的训练方法 信息的缩放程度和原来的图大小不改变 ， 在所以不影响 测试图的大小， 而缩放的训练方法 则改变了训练的方法 因此实际上会影响 测试图的大小        path, nameext = os.path.split(image)        image,gt = self.read_file(image,gt)        #返回一个numpy数组，0-255 uint8 类型         if self.crop_traindata:            image,gt = self.crop_image(image),self.crop_image(gt)        if self.resize_traindata is not None:            image = self.resize_image(image)            gt = self.resize_image(gt, "near")        image_tensor = self.np2tensor(image)        gt_tensor  = self.np2tensor(gt)        #gt_tensor = self.single_channel_to_onehot(gt)        return image_tensor, gt_tensor , nameextif __name__ == '__main__':    from src.option import args    args.dataset_path = "/home/liangshubo/Project/CTSR/dataset"    args.argument_scale = 2    args.scale = 4    args.patch_size = 192    MAX_DISPLAY_HEIGHT = 800  # 窗口最大高度（自动缩放适配）    dataset = SRBenchmark(args, test_dataset_name="CT0_BLUR_K5S1_AREA_X4")    for i in range(len(dataset)):        image, label,Name = dataset.__getitem__(i)        print(" Dataset Raw Image shape : [", image.shape, "] Max : ", image.max(), "ImageName",              dataset.image_path_list[15])        print(" Dataset Raw Label(onehot) shape :  [", label.shape, "] Max :", label.max())        image, label = image * 255, label * 255        lr_np = image.squeeze().cpu().numpy().astype(np.uint8)  # [1,H,W] → [H,W]        hr_np = label.squeeze().cpu().numpy().astype(np.uint8)        # cv2.imshow("lr_np", lr_np)        # cv2.imshow("hr_np", hr_np)        # cv2.waitKey(0)        # cv2.destroyAllWindows()